sqlReaderQuery.value:
@concat(
  'SELECT c.Id AS countryId, c.OldCountryId, c.Name AS CountryName, s.Id AS StateId, s.Name AS SateName, s.StateCode, tz.Id AS timezoneId, ''DBB2B672-0219-4605-8088-9C5A8D844C45'' AS DefaultLanguage FROM Countries c JOIN States s ON c.Id = s.CountryId JOIN TimeZones tz ON tz.CountryId = c.Id WHERE c.OldCountryId = ',
  string(item().OldCountryId)
)
